function hasAndrewsCnvCnnBackAndForthFixedValenceEvidence(input = null, embeddedGate = null) {
    if (!input || typeof input !== "object") {
        return false;
    }
    if (
        embeddedGate
        && typeof embeddedGate === "object"
        && String(embeddedGate.status || "pass") !== "blocked"
        && embeddedGate.routeRankingAllowed !== false
        && embeddedGate.generationAllowed !== false
    ) {
        return true;
    }
    const entradaGrammarObject = getAndrewsCnvCnnBackAndForthEntradaGrammarObject(input);
    const frames = getAndrewsCnvCnnBackAndForthRouteActionFrameCandidates(input);
    const directObjectPressureVector = collectAndrewsCnvCnnBackAndForthDirectObjectPressureVector(input);
    if (directObjectPressureVector) {
        const hasObjectSlotEvidence = hasAndrewsCnvCnnBackAndForthObjectSlotFormulaEvidence(input, frames);
        const objectSlotEvidenceCoversPressure = hasAndrewsCnvCnnBackAndForthObjectSlotFormulaEvidence(
            input,
            frames,
            directObjectPressureVector
        );
        const formulaSlotCoverageFixesPressure = hasAndrewsCnvCnnBackAndForthFormulaSlotObjectCoverageEvidence(
            input,
            frames,
            directObjectPressureVector
        );
        if (hasObjectSlotEvidence && !objectSlotEvidenceCoversPressure) {
            return false;
        }
        if (
            hasAndrewsCnvCnnBackAndForthExplicitValenceFrameFixedEvidence(input)
            || hasAndrewsCnvCnnBackAndForthRouteFrameValenceEvidence(frames)
            || formulaSlotCoverageFixesPressure
        ) {
            return true;
        }
        return false;
    }
    if (entradaGrammarObjectHasFixedValenceEvidence(entradaGrammarObject)) {
        return true;
    }
    if (entradaGrammarObjectHasValenceObjectSignal(entradaGrammarObject)) {
        return hasAndrewsCnvCnnBackAndForthExplicitValenceFrameFixedEvidence(input);
    }
    if (hasAndrewsCnvCnnBackAndForthExplicitValenceFrameFixedEvidence(input)) {
        return true;
    }
    if (hasAndrewsCnvCnnBackAndForthRouteFrameValenceEvidence(frames)) {
        return true;
    }
    if (hasAndrewsCnvCnnBackAndForthFormulaObjectSlotPositionEvidenceInSources(input, frames)) {
        return true;
    }
    return false;
}

function getAndrewsCnvCnnBackAndForthFunctionUseValenceGateStatus(embeddedGate = null) {
    if (!embeddedGate || typeof embeddedGate !== "object") {
        return "pass";
    }
    if (
        String(embeddedGate.status || "") === "blocked"
        || embeddedGate.routeRankingAllowed === false
        || embeddedGate.generationAllowed === false
    ) {
        return "blocked";
    }
    return String(embeddedGate.status || "pass");
}

function buildAndrewsCnvCnnBackAndForthRouteActionFunctionUseValenceGate(input = null, gates = []) {
    const gateDomains = getAndrewsCnvCnnBackAndForthRouteActionGateDomains(gates);
    const functionUseSignal = hasAndrewsCnvCnnBackAndForthFunctionUseSignal(input);
    const valenceObjectSignal = hasAndrewsCnvCnnBackAndForthValenceObjectSignal(input, gateDomains);
    if (!functionUseSignal || !valenceObjectSignal) {
        return null;
    }
    const embeddedGate = getAndrewsCnvCnnBackAndForthEmbeddedFunctionUseValenceGate(input);
    const embeddedStatus = getAndrewsCnvCnnBackAndForthFunctionUseValenceGateStatus(embeddedGate);
    const status = embeddedGate
        ? embeddedStatus
        : (hasAndrewsCnvCnnBackAndForthFixedValenceEvidence(input, embeddedGate) ? "pass" : "blocked");
    const reason = embeddedGate
        ? String(embeddedGate.reason || (status === "blocked"
            ? "route-action-embedded-function-use-valence-gate-blocked"
            : "route-action-embedded-function-use-valence-gate-passed"))
        : (status === "blocked"
            ? "route-action-function-use-valence-frame-unfixed"
            : "route-action-function-use-valence-frame-fixed");
    return {
        kind: "andrews-cnv-cnn-route-action-function-use-valence-gate",
        version: 1,
        status,
        diagnosticId: ANDREWS_CNV_CNN_FUNCTION_USE_VALENCE_OBJECT_GATE_DIAGNOSTIC_ID,
        routeStage: ANDREWS_CNV_CNN_FUNCTION_USE_VALENCE_OBJECT_GATE_ROUTE_STAGE,
        reason,
        routeRankingAllowed: status !== "blocked",
        generationAllowed: status !== "blocked",
        requiresFixedValenceFrame: true,
        gateDomains,
        functionUseSignal,
        valenceObjectSignal,
        embeddedFunctionUseValenceGate: embeddedGate || null,
        boundaries: {
            functionUseCannotConsumeValenceObject: true,
            functionUseCannotDeleteValenceObject: true,
            functionUseCannotInventValenceObject: true,
            functionUseCannotRelocateValenceObject: true,
            functionUseCannotReclassifyValenceObject: true,
            functionUseMayAnnotateLicensedReadingsOnly: true,
            unresolvedValenceFrameIsHardGate: true,
        },
    };
}

function buildAndrewsCnvCnnBackAndForthRouteActionContract(input = null, {
    routeRecordId = "",
    sourceRequirementIds = [],
    obstacleLimit = 8,
    sourceUnit = "",
    targetUnit = "",
    generationAllowed = null,
    diagnosticOnly = false,
} = {}) {
    const resolvedRouteId = String(routeRecordId || inferAndrewsCnvCnnBackAndForthRouteRecordId(input) || "").trim();
    const record = getAndrewsCnvCnnBackAndForthRouteRecordById(resolvedRouteId);
    if (!record) {
        return null;
    }
    const routeSourceRequirements = Array.isArray(input?.sourceRequirement?.requirements)
        ? input.sourceRequirement.requirements.map((entry) => String(entry?.id || entry || "").trim()).filter(Boolean)
        : [];
    const routeDiagnosticIds = Array.isArray(input?.routeDiagnostics)
        ? input.routeDiagnostics.map((entry) => String(entry?.id || entry?.code || "").trim()).filter(Boolean)
        : [];
    const datasetGateIds = input?.dataset && typeof input.dataset === "object"
        ? Object.keys(input.dataset).filter((key) => Boolean(input.dataset[key]))
        : [];
    const gateSeedIds = [
        ...sourceRequirementIds,
        ...routeSourceRequirements,
        ...routeDiagnosticIds,
        ...datasetGateIds,
    ].map((entry) => String(entry || "").trim()).filter(Boolean);
    const gates = getAndrewsCnvCnnBackAndForthObstacleGatesForRoute(resolvedRouteId, {
        sourceRequirementIds: gateSeedIds,
        limit: obstacleLimit,
    });
    const entradaGrammarObject = getAndrewsCnvCnnBackAndForthEntradaGrammarObject(input);
    const functionUseValenceGate = buildAndrewsCnvCnnBackAndForthRouteActionFunctionUseValenceGate(input, gates);
    const routeRankingAllowed = functionUseValenceGate?.routeRankingAllowed !== false;
    const resolvedGenerationAllowed = generationAllowed === null
        ? null
        : generationAllowed === true && routeRankingAllowed;
    const routeCoordinateFrame = buildAndrewsCnvCnnBackAndForthRouteCoordinateFrame(record);
    return {
        kind: "andrews-cnv-cnn-route-action-contract",
        version: 1,
        routeRecordId: record.id,
        routeKind: record.routeKind,
        transition: record.transition,
        sourceUnit: sourceUnit || record.sourceUnit,
        targetUnit: targetUnit || record.targetUnit,
        pdfSearchTerm: record.pdfSearchTerm,
        andrewsRefs: Array.from(record.andrewsRefs || []),
        directiveEs: record.directiveEs,
        requiredBoundary: record.requiredBoundary,
        routeCoordinateFrame,
        sourceRouteFrame: routeCoordinateFrame,
        routeFrame: routeCoordinateFrame,
        sourceRouteFrameRequired: true,
        sourceRequirementGateIds: gateSeedIds,
        obstacleGateIds: gates.map((entry) => entry.id),
        obstacleGates: gates,
        entradaGrammarObject: cloneAndrewsCnvCnnBackAndForthEntradaGrammarObject(entradaGrammarObject),
        entradaGrammarLayerOrder: Array.isArray(entradaGrammarObject?.layerOrder)
            ? Array.from(entradaGrammarObject.layerOrder)
            : [],
        functionUseValenceGate,
        routeRankingAllowed,
        generationAllowed: resolvedGenerationAllowed,
        diagnosticOnly: diagnosticOnly === true || routeRankingAllowed !== true,
    };
}

function isAndrewsCnvCnnBackAndForthProbeAvailable(probe = "") {
    switch (String(probe || "")) {
        case "buildLesson36NominalizedVncPursuitFrame":
            return typeof buildLesson36NominalizedVncPursuitFrame === "function";
        case "buildLesson37DeverbalNounstemPursuitFrame":
            return typeof buildLesson37DeverbalNounstemPursuitFrame === "function";
        case "getNawatDenominalAndrewsContractInventory":
            return typeof getNawatDenominalAndrewsContractInventory === "function";
        case "generateNawatDenominalAndrewsContractRoutePreview":
            return typeof generateNawatDenominalAndrewsContractRoutePreview === "function";
        case "buildLesson41AdjectivalNncPursuitFrame":
            return typeof buildLesson41AdjectivalNncPursuitFrame === "function";
        default:
            return false;
    }
}

function getAndrewsCnvCnnBackAndForthProbeStatus(record = null) {
    const probe = String(record?.implementationProbe || "");
    const available = isAndrewsCnvCnnBackAndForthProbeAvailable(probe);
    if (!available) {
        return {
            probe,
            available: false,
            coverage: "missing",
            obstacle: `Falta el punto de inspección ${probe}.`,
        };
    }
    if (probe === "getNawatDenominalAndrewsContractInventory") {
        const inventory = getNawatDenominalAndrewsContractInventory();
        const sourceLimitedCount = Array.isArray(inventory)
            ? inventory.filter((entry) => (
                /source-evidence/i.test(String(entry?.generationStatus || entry?.supportStatus || ""))
                || Object.keys(entry?.boundaries || {}).some((key) => /source/i.test(String(key)))
            )).length
            : 0;
        return {
            probe,
            available: true,
            coverage: "partial",
            contractCount: Array.isArray(inventory) ? inventory.length : 0,
            sourceLimitedCount,
            obstacle: "La ruta CNN -> CNV conserva contratos y compuertas, pero no equivale a generación finita completa.",
        };
    }
    if (probe === "generateNawatDenominalAndrewsContractRoutePreview") {
        const preview = generateNawatDenominalAndrewsContractRoutePreview({ sourceStem: "kal" });
        const routes = Array.isArray(preview?.routes) ? preview.routes : [];
        const deverbalTargets = routes.filter((route) => /deverbal/i.test(String(route.contractId || route.routeKind || "")));
        return {
            probe,
            available: true,
            coverage: deverbalTargets.length ? "partial" : "obstacle",
            targetCount: routes.length,
            deverbalTargetCount: deverbalTargets.length,
            obstacle: deverbalTargets.length
                ? "Los blancos deverbales existen como vista previa; requieren fuente verbal previa antes de generación finita."
                : "No se hallaron blancos ti-ya/hui-ya deverbales en la vista previa.",
        };
    }
    if (probe === "buildLesson36NominalizedVncPursuitFrame") {
        const frame = buildLesson36NominalizedVncPursuitFrame();
        return {
            probe,
            available: true,
            coverage: frame?.implementationState || "partial",
            remainingGapCount: Array.isArray(frame?.remainingGaps) ? frame.remainingGaps.length : 0,
            obstacle: "La nominalización funcional CNV -> CNN sigue separada de los troncos nominales deverbales.",
        };
    }
    if (probe === "buildLesson37DeverbalNounstemPursuitFrame") {
        const frame = buildLesson37DeverbalNounstemPursuitFrame();
        return {
            probe,
            available: true,
            coverage: frame?.implementationState || "partial",
            remainingGapCount: Array.isArray(frame?.remainingGaps) ? frame.remainingGaps.length : 0,
            obstacle: "La ruta CNV-core -> CNN deverbal es parcial y debe seguir bloqueando cobertura completa sin evidencia.",
        };
    }
    if (probe === "buildLesson41AdjectivalNncPursuitFrame") {
        const frame = buildLesson41AdjectivalNncPursuitFrame();
        return {
            probe,
            available: true,
            coverage: frame?.implementationState || "partial",
            remainingGapCount: Array.isArray(frame?.remainingGaps) ? frame.remainingGaps.length : 0,
            routeExpansionNote: "El bucle CNV -> CNN -> CNV conserva pruebas ejecutables para 40.10-40.11 y 41.3; la cobertura completa de Lesson 41 sigue siendo parcial.",
        };
    }
    return {
        probe,
        available: true,
        coverage: "unknown",
        obstacle: "Punto de inspección disponible sin resumen específico.",
    };
}

function summarizeAndrewsCnvCnnBackAndForthGeneratedResult(result = null) {
    if (!result || typeof result !== "object") {
        return {
            available: false,
            ok: false,
            surfaceForms: [],
            formulaEcho: "",
            unitKind: "",
            routeFamily: "",
            nominalizationKind: "",
            denominalFamily: "",
        };
    }
    return {
        available: true,
        ok: result.error ? false : result.ok !== false,
        surfaceForms: Array.isArray(result.surfaceForms)
            ? Array.from(result.surfaceForms)
            : (result.result ? [String(result.result)] : []),
        formulaEcho: result.nuclearClauseShell?.formulaEcho || "",
        unitKind: result.grammarFrame?.unitFrame?.unitKind || result.nuclearClauseShell?.clauseKind || "",
        routeFamily: result.grammarFrame?.routeContract?.routeFamily || result.generationRoute || "",
        nominalizationKind: result.nominalizationProfile?.role?.nominalizationKind || "",
        denominalFamily: result.denominalFamilyProfile?.routeFamily || "",
    };
}

function buildAndrewsCnvCnnSynonymLoopProbe() {
    const examples = [
        { stem: "chichiktiya", expectedResult: "chichiktik", expectedLessonRef: "Andrews 40.10", expectedSynonymSetKind: "pair" },
        { stem: "melaztiya", expectedResult: "melaztik", expectedLessonRef: "Andrews 40.11", expectedSynonymSetKind: "triplet" },
    ].map((example) => {
        const result = typeof generateRootPlusYaAdjectivalNncOutput === "function"
            ? generateRootPlusYaAdjectivalNncOutput({ stem: example.stem })
            : null;
        const sourceFrame = result?.rootPlusYaAdjectivalNncFrame?.sourceFormationFrame || null;
        const hit = Boolean(result)
            && result.supported === true
            && result.result === example.expectedResult
            && sourceFrame?.lessonRef === example.expectedLessonRef
            && sourceFrame?.sourceFormationSubtype === "denominal-tiya"
            && sourceFrame?.synonymSetKind === example.expectedSynonymSetKind
            && sourceFrame?.outputContract === "generate-current-source-only"
            && sourceFrame?.doesNotGenerateSiblingForms === true;
        return {
            stem: example.stem,
            expectedResult: example.expectedResult,
            result: result?.result || "",
            formulaEcho: result?.formulaEcho || "",
            sourceFormationSubtype: sourceFrame?.sourceFormationSubtype || "",
            sourceLessonRef: sourceFrame?.lessonRef || "",
            sourcePattern: sourceFrame?.sourcePattern || "",
            andrewsSourcePattern: sourceFrame?.andrewsSourcePattern || "",
            synonymSetKind: sourceFrame?.synonymSetKind || "",
            outputContract: sourceFrame?.outputContract || "",
            doesNotGenerateSiblingForms: sourceFrame?.doesNotGenerateSiblingForms === true,
            hit,
        };
    });
    return {
        id: "engine-path-cnv-cnn-cnv-synonym-loops",
        routeId: "cnv-to-cnn-to-cnv-loop",
        transition: "CNV core -> CNN deverbal nounstem -> CNV denominal verbstem",
        available: examples.every((entry) => entry.result),
        ok: examples.every((entry) => entry.hit),
        unitKind: "nominal-nuclear-clause",
        routeFamily: "adjectival-nnc",
        nominalizationKind: "preterit-agentive",
        denominalFamily: "denominal-tiya",
        examples,
        hit: examples.every((entry) => entry.hit),
    };
}

function buildAndrewsCnvCnnDenominalCompoundLoopProbe() {
    const generated = typeof generateRootPlusYaAdjectivalNncOutput === "function"
        ? generateRootPlusYaAdjectivalNncOutput({ stem: "(xilo/tzon/tiya)" })
        : null;
    const sourceFrame = generated?.denominalCompoundSourceFrame || null;
    const direct = typeof buildDenominalCompoundAdjectivalNncFunctionOutput === "function"
        ? buildDenominalCompoundAdjectivalNncFunctionOutput({
            denominalCompoundSurface: generated?.result || "",
            sourceDenominalCompoundFrame: sourceFrame,
            formulaSlots: generated?.formulaSlots || null,
            formulaEcho: generated?.formulaEcho || "",
        })
        : null;
    const functionFrame = direct?.adjectivalNncFunctionFrame || null;
    const hit = Boolean(generated && direct)
        && generated.supported === true
        && generated.result === "xilotzontik"
        && sourceFrame?.kind === "denominal-compound-nounstem-frame"
        && sourceFrame?.lessonRef === "Andrews 41.3"
        && sourceFrame?.operation?.type === "denominal-verbstem"
        && sourceFrame?.operation?.suffix === "ti"
        && sourceFrame?.operation?.nawatInputSuffix === "tiya"
        && sourceFrame?.matrix?.stem === "tzon"
        && Array.isArray(sourceFrame?.embeds)
        && sourceFrame.embeds.some((entry) => entry?.role === "adjacent-compound-noun-embed" && entry?.value === "xilo")
        && direct.supported === true
        && direct.result === generated.result
        && functionFrame?.functionKind === "denominal-compound-adjectival"
        && functionFrame?.sourceDenominalCompoundFrame?.matrix?.stem === "tzon";
    return {
        id: "engine-path-cnv-cnn-cnv-denominal-compound-loop",
        routeId: "cnv-to-cnn-to-cnv-loop",
        transition: "CNN compound nounstem -> CNV denominal verbstem -> CNN preterit-agentive adjectival output",
        available: Boolean(generated && direct),
        ok: hit,
        sourceInput: sourceFrame?.sourceInput?.rawInput || "",
        generatedVerbstem: sourceFrame?.generatedVerbstem || "",
        generatedSurface: generated?.result || "",
        formulaEcho: generated?.formulaEcho || "",
        unitKind: "nominal-nuclear-clause",
        routeFamily: direct?.grammarFrame?.routeContract?.routeFamily || direct?.generationRoute || "",
        nominalizationKind: functionFrame?.nominalizationKind || "",
        denominalFamily: "denominal-compound-tiya",
        sourceFrameKind: sourceFrame?.kind || "",
        sourceLessonRef: sourceFrame?.lessonRef || "",
        operationSuffix: sourceFrame?.operation?.suffix || "",
        operationNawatSuffix: sourceFrame?.operation?.nawatInputSuffix || "",
        sourceMatrixStem: sourceFrame?.matrix?.stem || "",
        sourceEmbedRoles: Array.isArray(sourceFrame?.embeds) ? sourceFrame.embeds.map((entry) => entry.role) : [],
        functionKind: functionFrame?.functionKind || "",
        hit,
    };
}

function buildAndrewsCnvCnnBackAndForthEnginePathProbes() {
    const probes = [];
    const canGenerate = typeof generateWord === "function";
    const nounMode = typeof TENSE_MODE === "object" && TENSE_MODE?.sustantivo
        ? TENSE_MODE.sustantivo
        : "sustantivo";
    const adjectiveMode = typeof TENSE_MODE === "object" && TENSE_MODE?.adjetivo
        ? TENSE_MODE.adjetivo
        : "adjetivo";
    const activeDerivationMode = typeof DERIVATION_MODE === "object" && DERIVATION_MODE?.active
        ? DERIVATION_MODE.active
        : "active";
    const activeVoiceMode = typeof VOICE_MODE === "object" && VOICE_MODE?.active
        ? VOICE_MODE.active
        : "active";
    const runGenerateWordProbe = ({
        id,
        routeId,
        transition,
        tiempo,
        tronco,
        expectedUnitKind,
        expectedRouteFamily,
        expectedNominalizationKind,
    }) => {
        let result = null;
        if (canGenerate) {
            result = generateWord({
                silent: true,
                skipValidation: true,
                override: { tenseMode: nounMode },
                posicionesFormula: {
                    pers1: "",
                    obj1: "",
                    tronco,
                    pers2: "",
                    num2: "",
                    poseedor: "",
                    tiempo,
                },
            });
        }
        const summary = summarizeAndrewsCnvCnnBackAndForthGeneratedResult(result);
        probes.push({
            id,
            routeId,
            transition,
            expectedUnitKind,
            expectedRouteFamily,
            expectedNominalizationKind,
            ...summary,
            hit: summary.available
                && summary.unitKind === expectedUnitKind
                && summary.routeFamily === expectedRouteFamily
                && summary.nominalizationKind === expectedNominalizationKind,
        });
    };
    runGenerateWordProbe({
        id: "engine-path-agentivo-presente",
        routeId: "cnv-predicate-to-cnn-nounstem-nominalization",
        transition: "CNV predicate -> CNN nounstem",
        tiempo: "agentivo-presente",
        tronco: "nemi",
        expectedUnitKind: "nominal-nuclear-clause",
        expectedRouteFamily: "present-agentive",
        expectedNominalizationKind: "present-agentive",
    });
    runGenerateWordProbe({
        id: "engine-path-sustantivo-verbal",
        routeId: "cnv-core-to-cnn-nounstem-deverbal",
        transition: "CNV core -> CNN nounstem",
        tiempo: "sustantivo-verbal",
        tronco: "nemi",
        expectedUnitKind: "nominal-nuclear-clause",
        expectedRouteFamily: "action-nominal",
        expectedNominalizationKind: "action-nominal",
    });
    let denominalResult = null;
    if (typeof executeGenerateWordRequest === "function") {
        denominalResult = executeGenerateWordRequest({
            options: {
                silent: true,
                skipValidation: false,
                override: {
                    tenseMode: adjectiveMode,
                    derivationMode: activeDerivationMode,
                    voiceMode: activeVoiceMode,
                },
            },
            posicionesFormula: {
                pers1: "",
                obj1: "",
                tronco: "(pusuni)",
                pers2: "",
                num2: "",
                poseedor: "",
                tiempo: "adjetivo-preterito-tik",
            },
            entradaTronco: {
                tieneControlTronco: false,
                valorTronco: "",
            },
        });
    }
    const denominalSummary = summarizeAndrewsCnvCnnBackAndForthGeneratedResult(denominalResult);
    probes.push({
        id: "engine-path-denominal-vi-ti",
        routeId: "cnn-nounstem-to-cnv-verbstem-denominal",
        transition: "CNN nounstem -> CNV verbstem",
        expectedUnitKind: "verbal-nuclear-clause",
        expectedRouteFamily: "adjectival-surface",
        expectedDenominalFamily: "vi-ti",
        ...denominalSummary,
        hit: denominalSummary.available
            && denominalSummary.unitKind === "verbal-nuclear-clause"
            && denominalSummary.denominalFamily === "vi-ti",
    });
    let preview = null;
    if (typeof generateNawatDenominalAndrewsContractRoutePreview === "function") {
        preview = generateNawatDenominalAndrewsContractRoutePreview({ sourceStem: "kal" });
    }
    const previewRoutes = Array.isArray(preview?.routes) ? preview.routes : [];
    probes.push({
        id: "engine-path-deverbal-verbstem-preview",
        routeId: "cnv-verbstem-to-cnv-verbstem-deverbal",
        transition: "CNV verbstem -> CNV verbstem",
        available: Boolean(preview),
        ok: Boolean(preview),
        sourceStem: preview?.sourceStem || "",
        routeCount: previewRoutes.length,
        sourceEvidenceRequiredCount: previewRoutes.filter((route) => route.finiteGenerationRequiresSourceEvidence === true).length,
        deverbalRouteCount: previewRoutes.filter((route) => /deverbal/i.test(String(route.contractId || ""))).length,
        hit: previewRoutes.filter((route) => /deverbal/i.test(String(route.contractId || ""))).length > 0,
    });
    probes.push(buildAndrewsCnvCnnSynonymLoopProbe());
    probes.push(buildAndrewsCnvCnnDenominalCompoundLoopProbe());
    return probes;
}

function buildAndrewsCnvCnnBackAndForthAudit() {
    const routeRecords = getAndrewsCnvCnnBackAndForthRouteRecords();
    const obstacleCatalog = getAndrewsCnvCnnBackAndForthObstacleCatalog();
    const dimensionalIndex = buildAndrewsCnvCnnBackAndForthDimensionalIndex();
    const resistanceStatistics = buildAndrewsCnvCnnBackAndForthResistanceStatistics();
    const obstacleCatalogRouteCounts = routeRecords.map((record) => ({
        routeId: record.id,
        count: obstacleCatalog.filter((entry) => entry.routeId === record.id).length,
    }));
    const obstacleCatalogRouteGaps = obstacleCatalogRouteCounts
        .filter((entry) => entry.count === 0)
        .map((entry) => entry.routeId);
    const probeStatuses = routeRecords.map((record) => ({
        routeId: record.id,
        ...getAndrewsCnvCnnBackAndForthProbeStatus(record),
    }));
    const enginePathProbes = buildAndrewsCnvCnnBackAndForthEnginePathProbes();
    const obstacles = probeStatuses
        .map((status) => status.obstacle || "")
        .concat(enginePathProbes.map((probe) => probe.hit === true ? "" : probe.obstacle || "Falta sonda de ruta ejecutable."))
        .filter(Boolean);
    return {
        kind: "andrews-cnv-cnn-back-and-forth-audit",
        version: 1,
        pdfSearchTerms: ["deverbal nounstem", "denominal verbstem", "deverbal verbstem"],
        grammarAuthority: "Andrews PDF",
        spellingAuthority: "Nawat/Pipil evidence",
        formalClasses: ["CNV", "CNN", "Partícula"],
        dimensionSystem: dimensionalIndex.dimensionSystem,
        routeRecords,
        routeCoordinateFrames: dimensionalIndex.routeCoordinateFrames,
        obstacleCatalog,
        obstacleCatalogCount: obstacleCatalog.length,
        obstacleCatalogPageCount: new Set(obstacleCatalog.flatMap((entry) => entry.pdfPages || [])).size,
        obstacleCatalogEntriesMissingPdfPages: obstacleCatalog
            .filter((entry) => !Array.isArray(entry.pdfPages) || entry.pdfPages.length === 0)
            .map((entry) => entry.id),
        obstacleCatalogRouteCounts,
        obstacleCatalogRouteGaps,
        dimensionalIndex,
        formulaFeatureIndex: resistanceStatistics.formulaFeatureIndex,
        resistanceStatistics,
        leastResistanceRoute: resistanceStatistics.leastResistanceRoute,
        mostResistanceRoute: resistanceStatistics.mostResistanceRoute,
        resistanceConversionPlan: resistanceStatistics.resistanceConversionPlan,
        equationPatternAnalysis: resistanceStatistics.equationPatternAnalysis,
        relationshipDiscoveryAnalysis: resistanceStatistics.relationshipDiscoveryAnalysis,
        probeStatuses,
        enginePathProbes,
        enginePathProbeCount: enginePathProbes.length,
        enginePathHitCount: enginePathProbes.filter((probe) => probe.hit === true).length,
        obstacleCount: obstacles.length,
        obstacles,
        antiConflationRules: [
            "Adjetival y adverbial son funciones o usos de ruta, no son clases formales.",
            "El tronco nominal deverbal es núcleo CNV -> tronco CNN, no un predicado CNV reetiquetado.",
            "El tronco verbal denominal es tronco CNN -> tronco CNV y debe conservar compuertas de evidencia de fuente.",
            "El tronco verbal deverbal de Andrews 54.2.3.b es tronco CNV -> tronco CNV y requiere la fuente previa ti/hui.",
            "La superficie puede escribirse en Nawat/Pipil; el orden de ranuras y la transición categorial siguen dirigidos por Andrews.",
        ],
    };
}

